/*
struct Node {
    int val; 
    Node *left;
    Node *right;

    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
}; */

class Solution {
  public:
    Node* createBST(vector<int> &nums) {
        if(nums.size() == 0) 
            return NULL;
        if(nums.size() == 1) {
            return new Node(nums[0]);
        }

        int middle = nums.size()/2;
        Node* root = new Node(nums[middle]);

        vector<int> leftInts(nums.begin(), nums.begin()+middle);
        vector<int> rightInts(nums.begin()+middle+1, nums.end());

        root->left = createBST(leftInts);
        root->right = createBST(rightInts);

        return root;
    }
};

