public class Solution {
    // Function to create BST from sorted array
    public static Node createBST(int[] nums) {
        return createBSTHelper(nums, 0, nums.length - 1);
    }

    private static Node createBSTHelper(int[] nums, int left, int right) {
        if (left > right) return null;

        int mid = (left + right) / 2;
        Node root = new Node(nums[mid]);

        root.left = createBSTHelper(nums, left, mid - 1);
        root.right = createBSTHelper(nums, mid + 1, right);

        return root;
    }
}

