class Solution {
    createBST(nums) {
        if (nums.length === 0)
            return null;
        if (nums.length === 1) {
            return new Node(nums[0]);
        }

        let middle = Math.floor(nums.length / 2);
        let root = new Node(nums[middle]);

        let leftInts = nums.slice(0, middle);
        let rightInts = nums.slice(middle + 1);

        root.left = this.createBST(leftInts);
        root.right = this.createBST(rightInts);

        return root;
    }
}
